#include<bits/stdc++.h>
using namespace std;
string A,B;
int a[1000],b[1000];
int main()
{
	cin>>A>>B;
    reverse(A.begin(),A.end());
    reverse(B.begin(),B.end());
    for(int i=0;i<A.length();i++)a[i]=A[i]-'0';
    for(int i=0;i<B.length();i++)b[i]=B[i]-'0';
    int len=max(A.length(),B.length());
    for(int i=0;i<len;i++)a[i]+=b[i];
    for(int i=0;i<len;i++){
    	if(a[i]>=10){
        	a[i]-=10;
            a[i+1]+=1;
            if(i==len-1){
            	len++;
            }
        }
    }
    for(int i=len-1;i>=0;i--){
    	cout<<a[i];
    }
}
